function newChaseDir(actor: Actor): void {
  if (!actor.target) sysError('newChaseDir: called with no target');
  const turn = opposite[actor.moveDir];
  const dx = actor.target.x - actor.x;
  const dy = actor.target.y - actor.y;
  const d: number[] = [DI_NODIR, DI_NODIR, DI_NODIR];
  if (dx > 10 * FRACUNIT) d[1] = DI_EAST;
  else if (dx < -10 * FRACUNIT) d[1] = DI_WEST;
  if (dy < -10 * FRACUNIT) d[2] = DI_SOUTH;
  else if (dy > 10 * FRACUNIT) d[2] = DI_NORTH;
  if (d[1] !== DI_NODIR && d[2] !== DI_NODIR) {
    actor.moveDir = diags[((dy < 0) ? 2 : 0) + ((dx > 0) ? 1 : 0)];
    if (actor.moveDir !== turn && tryWalk(actor)) return;
  }
  if (pRandom() > 200 || Math.abs(dy) > Math.abs(dx)) { const t = d[1]; d[1] = d[2]; d[2] = t; }
  if (d[1] !== DI_NODIR && d[1] !== turn) { actor.moveDir = d[1]; if (tryWalk(actor)) return; }
  if (d[2] !== DI_NODIR && d[2] !== turn) { actor.moveDir = d[2]; if (tryWalk(actor)) return; }
  actor.moveDir = DI_NODIR; // can not move
}
